-- ============================================================
-- Layer 2: 主数据层 - 公司基本信息
-- ============================================================

CREATE TABLE IF NOT EXISTS companies (
    id                   SERIAL PRIMARY KEY,
    ts_code              VARCHAR(20)     NOT NULL UNIQUE,
    symbol               VARCHAR(10)     NOT NULL,
    name                 VARCHAR(50)     NOT NULL,
    full_name            VARCHAR(200),
    exchange             exchange_enum   NOT NULL,
    industry_sw_l1       VARCHAR(100),
    industry_sw_l2       VARCHAR(100),
    list_board           list_board_enum,
    list_date            DATE,
    register_address     VARCHAR(500),
    office_address       VARCHAR(500),
    legal_representative VARCHAR(100),
    main_business        TEXT,
    employees            INT,
    is_active            BOOLEAN         NOT NULL DEFAULT TRUE,
    is_listed            BOOLEAN         NOT NULL DEFAULT TRUE,
    source_id            INT             NOT NULL REFERENCES data_sources(id),
    created_at           TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_at           TIMESTAMPTZ     NOT NULL DEFAULT NOW()
);

COMMENT ON TABLE companies IS '公司基本信息表（公司身份标签）';
COMMENT ON COLUMN companies.ts_code IS '证券代码(交易所后缀)，如 000001.SZ / 600000.SH';
COMMENT ON COLUMN companies.symbol IS '纯数字代码，如 000001';
COMMENT ON COLUMN companies.name IS '证券简称';
COMMENT ON COLUMN companies.full_name IS '公司法定全称';
COMMENT ON COLUMN companies.exchange IS '交易所：SH=上海 / SZ=深圳 / BJ=北交所';
COMMENT ON COLUMN companies.industry_sw_l1 IS '申万一级行业分类';
COMMENT ON COLUMN companies.industry_sw_l2 IS '申万二级行业分类';
COMMENT ON COLUMN companies.list_board IS '上市板块';
COMMENT ON COLUMN companies.is_active IS '是否仍存续（退市=false）';
COMMENT ON COLUMN companies.is_listed IS '当前是否仍在交易中';
COMMENT ON COLUMN companies.source_id IS '数据来源，关联data_sources表';

CREATE INDEX idx_companies_industry_l1 ON companies(industry_sw_l1);
CREATE INDEX idx_companies_symbol ON companies(symbol);
CREATE INDEX idx_companies_exchange ON companies(exchange);

-- ============================================================
-- Layer 3: 原始数据层 - 资产负债表（宽表）
-- 
-- 【坑3 NULL vs 0】：所有数值字段 DEFAULT NULL
--   业务层 safe_divide(a, b) 函数：b IS NULL OR b=0 → RETURN NULL
--   不会因 NULL 被误判为 0 而导致 ROE/ROA 等指标失真
-- ============================================================

CREATE TABLE IF NOT EXISTS balance_sheet (
    id                    BIGSERIAL PRIMARY KEY,
    company_id            INT             NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
    report_date           DATE            NOT NULL,
    announcement_date     DATE,
    report_type           report_type_enum NOT NULL,

    -- 资产类
    total_assets          NUMERIC(20,4),
    current_assets        NUMERIC(20,4),
    non_current_assets    NUMERIC(20,4),
    cash_and_equivalents  NUMERIC(20,4),
    accounts_receivable   NUMERIC(20,4),
    inventory             NUMERIC(20,4),
    fixed_assets          NUMERIC(20,4),
    goodwill              NUMERIC(20,4),

    -- 负债类
    total_liabilities     NUMERIC(20,4),
    current_liabilities   NUMERIC(20,4),
    non_current_liabilities NUMERIC(20,4),
    short_term_borrowings NUMERIC(20,4),
    long_term_borrowings  NUMERIC(20,4),
    accounts_payable      NUMERIC(20,4),

    -- 权益类
    total_equity          NUMERIC(20,4),
    equity_parent         NUMERIC(20,4),      -- 归属于母公司股东权益
    capital_reserve       NUMERIC(20,4),      -- 资本公积
    surplus_reserve       NUMERIC(20,4),      -- 盈余公积
    undistributed_profit  NUMERIC(20,4),      -- 未分配利润

    -- 排雷相关
    impairment_loss_assets NUMERIC(20,4),     -- 资产减值损失（部分公司放在BS附注）

    source_id             INT             NOT NULL REFERENCES data_sources(id),
    created_at            TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    UNIQUE (company_id, report_date, report_type, source_id)
);

COMMENT ON TABLE balance_sheet IS '资产负债表（宽表）：一行=一个公司+一个报告期，所有科目作为列';
COMMENT ON COLUMN balance_sheet.total_assets IS '总资产';
COMMENT ON COLUMN balance_sheet.current_assets IS '流动资产';
COMMENT ON COLUMN balance_sheet.non_current_assets IS '非流动资产';
COMMENT ON COLUMN balance_sheet.cash_and_equivalents IS '货币资金 = 现金及银行存款等';
COMMENT ON COLUMN balance_sheet.accounts_receivable IS '应收账款：已销售未收回的货款';
COMMENT ON COLUMN balance_sheet.inventory IS '存货：库存商品、原材料等';
COMMENT ON COLUMN balance_sheet.fixed_assets IS '固定资产：房屋、机器设备等长期资产';
COMMENT ON COLUMN balance_sheet.goodwill IS '商誉：并购溢价，减值风险核心关注指标';
COMMENT ON COLUMN balance_sheet.total_liabilities IS '总负债';
COMMENT ON COLUMN balance_sheet.current_liabilities IS '流动负债：一年内到期的负债';
COMMENT ON COLUMN balance_sheet.non_current_liabilities IS '非流动负债：一年以上到期的负债';
COMMENT ON COLUMN balance_sheet.short_term_borrowings IS '短期借款：一年内到期的银行借款';
COMMENT ON COLUMN balance_sheet.long_term_borrowings IS '长期借款：一年以上到期的银行借款';
COMMENT ON COLUMN balance_sheet.accounts_payable IS '应付账款：已采购未支付的货款';
COMMENT ON COLUMN balance_sheet.total_equity IS '所有者权益（股东权益）= 总资产 - 总负债';
COMMENT ON COLUMN balance_sheet.equity_parent IS '归属于母公司股东权益：ROE分母、PB分母';
COMMENT ON COLUMN balance_sheet.capital_reserve IS '资本公积：股本溢价等资本性公积';
COMMENT ON COLUMN balance_sheet.surplus_reserve IS '盈余公积：从净利润中提取的法定/任意公积';
COMMENT ON COLUMN balance_sheet.undistributed_profit IS '未分配利润：累计未分配的净利润';
COMMENT ON COLUMN balance_sheet.impairment_loss_assets IS '资产减值损失：用于计算 资产减值损失/净利润 排雷指标';

CREATE INDEX idx_bs_company_date ON balance_sheet(company_id, report_date);
CREATE INDEX idx_bs_report_date ON balance_sheet(report_date);
CREATE INDEX idx_bs_company_source ON balance_sheet(company_id, source_id);

-- ============================================================
-- Layer 3: 原始数据层 - 利润表（宽表）
-- 
-- 【坑3 NULL vs 0】：所有数值字段 DEFAULT NULL
--   分母为NULL时指标结果为NULL，而非错误地除以0
-- ============================================================

CREATE TABLE IF NOT EXISTS income_statement (
    id                       BIGSERIAL PRIMARY KEY,
    company_id               INT             NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
    report_date              DATE            NOT NULL,
    announcement_date        DATE,
    report_type              report_type_enum NOT NULL,

    -- 收入与成本
    total_revenue            NUMERIC(20,4),     -- 营业总收入
    operating_revenue        NUMERIC(20,4),     -- 营业收入
    operating_cost           NUMERIC(20,4),     -- 营业成本
    gross_profit             NUMERIC(20,4),     -- 毛利润 = 营收 - 营业成本

    -- 利润层次
    operating_profit         NUMERIC(20,4),     -- 营业利润
    total_profit             NUMERIC(20,4),     -- 利润总额
    net_profit               NUMERIC(20,4),     -- 净利润
    net_profit_parent        NUMERIC(20,4),     -- 归属于母公司股东净利润（PE分母）
    net_profit_deducted      NUMERIC(20,4),     -- 扣除非经常性损益后净利润

    -- 收益明细
    operating_income_net     NUMERIC(20,4),     -- 经营活动净收益
    fair_value_change_income NUMERIC(20,4),     -- 公允价值变动净收益
    interest_expense         NUMERIC(20,4),     -- 利息费用（利息保障倍数分母）

    -- 每股指标（财报披露值）
    basic_eps_disclosed      NUMERIC(14,6),     -- 基本每股收益(披露值)
    diluted_eps_disclosed    NUMERIC(14,6),     -- 稀释每股收益(披露值)

    source_id                INT             NOT NULL REFERENCES data_sources(id),
    created_at               TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    UNIQUE (company_id, report_date, report_type, source_id)
);

COMMENT ON TABLE income_statement IS '利润表（宽表）：一行=一个公司+一个报告期';
COMMENT ON COLUMN income_statement.total_revenue IS '营业总收入：公司主营业务收入合计';
COMMENT ON COLUMN income_statement.operating_revenue IS '营业收入：销售商品或提供服务所得';
COMMENT ON COLUMN income_statement.operating_cost IS '营业成本：与营业收入对应的成本';
COMMENT ON COLUMN income_statement.gross_profit IS '毛利润 = 营业收入 - 营业成本';
COMMENT ON COLUMN income_statement.operating_profit IS '营业利润 = 营业收入 - 营业成本 - 期间费用等';
COMMENT ON COLUMN income_statement.total_profit IS '利润总额 = 营业利润 + 营业外收支';
COMMENT ON COLUMN income_statement.net_profit IS '净利润 = 利润总额 - 所得税';
COMMENT ON COLUMN income_statement.net_profit_parent IS '归母净利润：PE/ROE等核心指标的关键分母';
COMMENT ON COLUMN income_statement.net_profit_deducted IS '扣非净利润：剔除一次性损益后的真实盈利';
COMMENT ON COLUMN income_statement.interest_expense IS '利息费用：用于计算利息保障倍数 = EBIT / 利息费用';
COMMENT ON COLUMN income_statement.basic_eps_disclosed IS '基本每股收益(财报披露值)：可能与自主计算值有差异';
COMMENT ON COLUMN income_statement.diluted_eps_disclosed IS '稀释每股收益(披露值)：考虑潜在稀释因素';

CREATE INDEX idx_is_company_date ON income_statement(company_id, report_date);
CREATE INDEX idx_is_report_date ON income_statement(report_date);
CREATE INDEX idx_is_company_source ON income_statement(company_id, source_id);

-- ============================================================
-- Layer 3: 原始数据层 - 现金流量表（宽表）
-- ============================================================

CREATE TABLE IF NOT EXISTS cash_flow_statement (
    id                     BIGSERIAL PRIMARY KEY,
    company_id             INT             NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
    report_date            DATE            NOT NULL,
    announcement_date      DATE,
    report_type            report_type_enum NOT NULL,

    -- 三大现金流
    cf_operating           NUMERIC(20,4),      -- 经营活动产生的现金流量净额
    cf_investing           NUMERIC(20,4),      -- 投资活动产生的现金流量净额
    cf_financing           NUMERIC(20,4),      -- 筹资活动产生的现金流量净额
    cf_net_increase        NUMERIC(20,4),      -- 现金及现金等价物净增加额

    -- 每股与资本支出
    cf_operating_per_share NUMERIC(14,6),      -- 每股经营活动现金流(披露值)
    capex                  NUMERIC(20,4),      -- 资本支出（购建固定资产、无形资产等）

    source_id              INT             NOT NULL REFERENCES data_sources(id),
    created_at             TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    UNIQUE (company_id, report_date, report_type, source_id)
);

COMMENT ON TABLE cash_flow_statement IS '现金流量表（宽表）：一行=一个公司+一个报告期';
COMMENT ON COLUMN cash_flow_statement.cf_operating IS '经营活动现金流量净额：自由现金流计算基础，PCF分母';
COMMENT ON COLUMN cash_flow_statement.cf_investing IS '投资活动现金流量净额';
COMMENT ON COLUMN cash_flow_statement.cf_financing IS '筹资活动现金流量净额';
COMMENT ON COLUMN cash_flow_statement.cf_net_increase IS '现金及等价物净增加额';
COMMENT ON COLUMN cash_flow_statement.cf_operating_per_share IS '每股经营现金流(披露值)';
COMMENT ON COLUMN cash_flow_statement.capex IS '资本支出：用于计算自由现金流 FCF = 经营现金流 - 资本支出';

CREATE INDEX idx_cf_company_date ON cash_flow_statement(company_id, report_date);
CREATE INDEX idx_cf_report_date ON cash_flow_statement(report_date);
CREATE INDEX idx_cf_company_source ON cash_flow_statement(company_id, source_id);

-- ============================================================
-- Layer 3: 原始数据层 - 股本、分红、审计意见
-- ============================================================

-- 表: share_capital - 股本历史
CREATE TABLE IF NOT EXISTS share_capital (
    id                 BIGSERIAL PRIMARY KEY,
    company_id         INT             NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
    report_date        DATE            NOT NULL,
    total_shares       BIGINT,                         -- 总股本（股）
    float_shares       BIGINT,                         -- 流通股本
    restricted_shares  BIGINT,                         -- 限售股本
    a_shares           BIGINT,                         -- A股股本
    b_shares           BIGINT,                         -- B股股本
    h_shares           BIGINT,                         -- H股股本
    shareholder_count  INT,                            -- 股东总数
    source_id          INT             NOT NULL REFERENCES data_sources(id),
    created_at         TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    UNIQUE (company_id, report_date, source_id)
);

COMMENT ON TABLE share_capital IS '股本与股份数据：按报告期记录股本结构变化';
COMMENT ON COLUMN share_capital.total_shares IS '总股本：用于计算总市值=收盘价×总股本';
COMMENT ON COLUMN share_capital.float_shares IS '流通股本：用于计算流通市值=收盘价×流通股本';
COMMENT ON COLUMN share_capital.restricted_shares IS '限售股本：已发行但尚在限售期的股份';
COMMENT ON COLUMN share_capital.shareholder_count IS '股东总数：报告期末登记在册的股东人数';

CREATE INDEX idx_sc_company_date ON share_capital(company_id, report_date);

-- 表: dividend_records - 分红记录
CREATE TABLE IF NOT EXISTS dividend_records (
    id                    BIGSERIAL PRIMARY KEY,
    company_id            INT             NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
    ex_div_date           DATE            NOT NULL,        -- 除权除息日
    plan_announce_date    DATE,                             -- 预案公告日
    cash_div_per_share    NUMERIC(14,6),                    -- 每股现金分红（元）
    stock_div_ratio       NUMERIC(10,6),                    -- 送转股总比例
    total_cash_div        NUMERIC(20,4),                    -- 现金分红总额
    source_id             INT             NOT NULL REFERENCES data_sources(id),
    created_at            TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    UNIQUE (company_id, ex_div_date, source_id)
);

COMMENT ON TABLE dividend_records IS '分红记录表：用于计算股息率、分红融资比、股息支付率等';
COMMENT ON COLUMN dividend_records.cash_div_per_share IS '每股现金分红：用于计算股息率 = 近一年累计分红 / 股价';
COMMENT ON COLUMN dividend_records.total_cash_div IS '现金分红总额：用于股息支付率 = 分红总额 / 归母净利润';

CREATE INDEX idx_div_company_date ON dividend_records(company_id, ex_div_date);

-- 表: audit_opinions - 审计意见
CREATE TABLE IF NOT EXISTS audit_opinions (
    id             BIGSERIAL PRIMARY KEY,
    company_id     INT                NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
    report_date    DATE               NOT NULL,
    report_type    report_type_enum   NOT NULL,
    opinion_type   audit_opinion_enum NOT NULL,
    auditor        VARCHAR(200),                       -- 审计机构名称
    source_id      INT                NOT NULL REFERENCES data_sources(id),
    created_at     TIMESTAMPTZ        NOT NULL DEFAULT NOW(),
    UNIQUE (company_id, report_date, report_type, source_id)
);

COMMENT ON TABLE audit_opinions IS '审计意见表——排雷核心：非标准意见即回避';
COMMENT ON COLUMN audit_opinions.opinion_type IS '审计意见类型：标准无保留/带强调事项段/保留/否定/无法表示';
COMMENT ON COLUMN audit_opinions.auditor IS '审计机构名称';

CREATE INDEX idx_ao_company_date ON audit_opinions(company_id, report_date);

-- ============================================================
-- Layer 4: 衍生数据层 - 日频衍生指标（物化存储）
-- 估值指标 + 市场情绪指标
-- 每天收盘后由业务层批量刷新
-- ============================================================

CREATE TABLE IF NOT EXISTS derived_metrics_daily (
    id                      BIGSERIAL PRIMARY KEY,
    company_id              INT           NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
    trade_date              DATE          NOT NULL,

    -- 估值指标 (Category 7)
    total_mv                NUMERIC(20,4),      -- 总市值 = close × total_shares
    float_mv                NUMERIC(20,4),      -- 流通市值 = close × float_shares
    pe                      NUMERIC(14,4),      -- 市盈率（静态）= 总市值 / 归母净利润
    pe_ttm                  NUMERIC(14,4),      -- 滚动市盈率 = 总市值 / 近12月归母净利润
    pb                      NUMERIC(14,4),      -- 市净率 = 总市值 / 归母权益
    ps                      NUMERIC(14,4),      -- 市销率 = 总市值 / 营业总收入(TTM)
    pcf                     NUMERIC(14,4),      -- 市现率 = 总市值 / 经营现金流(TTM)
    peg                     NUMERIC(14,4),      -- PEG = PE-TTM / 归母净利润增速×100
    dividend_yield          NUMERIC(14,6),      -- 股息率 = 近一年分红总额 / 总市值
    ev_ebitda               NUMERIC(14,4),      -- EV/EBITDA

    -- 市场情绪指标 (Category 15)
    pe_history_percentile   NUMERIC(10,4),      -- PE历史分位点（过去N年）
    pb_history_percentile   NUMERIC(10,4),      -- PB历史分位点
    a_share_risk_premium    NUMERIC(10,4),      -- A股风险溢价 = (1/PE) - 10年国债收益率

    created_at              TIMESTAMPTZ   NOT NULL DEFAULT NOW(),
    UNIQUE (company_id, trade_date)
);

COMMENT ON TABLE derived_metrics_daily IS '日频衍生指标表（物化存储）：估值指标+市场情绪，每日收盘后全量刷新';
COMMENT ON COLUMN derived_metrics_daily.pe IS '静态市盈率：总市值/最新年报归母净利润。NULL=净利润为负或缺失';
COMMENT ON COLUMN derived_metrics_daily.pe_ttm IS '滚动市盈率：总市值/近12月归母净利润合计，比静态PE更及时';
COMMENT ON COLUMN derived_metrics_daily.pb IS '市净率：总市值/归母股东权益。银行业核心估值指标';
COMMENT ON COLUMN derived_metrics_daily.peg IS 'PEG = PE-TTM / (净利润增速×100)，<1表示可能被低估';
COMMENT ON COLUMN derived_metrics_daily.dividend_yield IS '股息率：近一年现金分红/总市值，红利策略核心指标';
COMMENT ON COLUMN derived_metrics_daily.pe_history_percentile IS 'PE历史分位点：当前PE在历史区间的百分位，>80%=高估，<20%=低估';

CREATE INDEX idx_dmd_company_date ON derived_metrics_daily(company_id, trade_date);
CREATE INDEX idx_dmd_trade_date ON derived_metrics_daily(trade_date);

-- ============================================================
-- Layer 4: 衍生数据层 - 成长性指标（物化存储）
-- Category 11
-- ============================================================

CREATE TABLE IF NOT EXISTS derived_metrics_growth (
    id                       BIGSERIAL PRIMARY KEY,
    company_id               INT               NOT NULL REFERENCES companies(id) ON DELETE CASCADE,
    report_date              DATE              NOT NULL,
    report_type              report_type_enum  NOT NULL,

    -- 成长性指标 (Category 11)
    revenue_yoy              NUMERIC(14,6),     -- 营收同比增长率
    net_profit_yoy           NUMERIC(14,6),     -- 归母净利润同比增长率
    deducted_net_profit_yoy  NUMERIC(14,6),     -- 扣非净利润同比增长率
    equity_yoy               NUMERIC(14,6),     -- 净资产增长率
    qoq_net_profit           NUMERIC(14,6),     -- 单季净利润环比增长率

    created_at               TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    UNIQUE (company_id, report_date, report_type)
);

COMMENT ON TABLE derived_metrics_growth IS '成长性指标表（物化存储）：同比增长率与环比增长率';
COMMENT ON COLUMN derived_metrics_growth.revenue_yoy IS '营收同比增长率：(本期营收-上年同期)/上年同期，反映业务规模扩张速度';
COMMENT ON COLUMN derived_metrics_growth.net_profit_yoy IS '归母净利润同比增长率：盈利增长核心指标，PEG计算的关键输入';
COMMENT ON COLUMN derived_metrics_growth.deducted_net_profit_yoy IS '扣非净利润同比增长率：剔除一次性损益后的真实增速';
COMMENT ON COLUMN derived_metrics_growth.equity_yoy IS '净资产增长率：净资产积累速度';
COMMENT ON COLUMN derived_metrics_growth.qoq_net_profit IS '单季净利润环比增长率：剔除基数效应的单季景气趋势指标';

CREATE INDEX idx_dmg_company_date ON derived_metrics_growth(company_id, report_date);
